THE CLAIM:
{
 "title": "Europe's PDU share is likely 24%, not the 30% assumed",
 "narrative": "The model builds its €320M chain by taking 30% of GVR's $2.81B global figure as Europe's share. But no source states that 30%, and the regional data points lower: the US alone is $579.7M of a $2.1B market, about 28% for one country. If Europe is closer to 24%, the Year-1 number and everything below it shrinks.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "The 30% Europe share is unsourced; GVR gives only 38% for North America",
   "refs": [
    "ledger:tamBase",
    "digest:tam-global-crosscheck#c1"
   ]
  },
  {
   "step": "propagation",
   "text": "US alone is 28% of the global market, and Germany grows at half the global rate",
   "refs": [
    "digest:tam-global-crosscheck#c15",
    "digest:tam-global-crosscheck#c13",
    "digest:tam-global-crosscheck#c14",
    "digest:tam-global-crosscheck#c0"
   ]
  },
  {
   "step": "model-impact",
   "text": "Europe at 24% shrinks the whole chain and SAM/YAM proportionally",
   "refs": [
    "ledger:tamBase"
   ]
  }
 ],
 "falsifier": "Any primary source stating Europe's rack-PDU revenue share at 28% or higher, such as the Omdia Rack PDU Annual Tracker regional table.",
 "category": "fact",
 "evidence": [
  {
   "title": "Data Center Rack Power Distribution Unit Market Report 2033",
   "sourceType": "industry-report",
   "publisher": "Grand View Research",
   "date": null,
   "excerpt": "North America held 38.0% revenue share of the global data center rack power distribution unit market. ... Asia Pacific: Fastest grow[ing]",
   "url": "https://www.grandviewresearch.com/industry-analysis/data-center-rack-power-distribution-unit-pdu-market",
   "attached": true
  },
  {
   "title": "Intelligent PDU — Global Strategic Business Report",
   "sourceType": "analyst-estimate",
   "publisher": "Global Industry Analysts",
   "date": "2025-10-01",
   "excerpt": "The Intelligent PDU market in the U.S. is estimated at US$579.7 Million in the year 2024. ... Within Europe, Germany is forecast to grow at approximately 5.2% CAGR.",
   "url": "https://www.marketresearch.com/Global-Industry-Analysts-v1039/Intelligent-PDU-42596267/",
   "attached": true
  },
  {
   "title": "Intelligent PDU Market Size, Share & 2030 Trends Report",
   "sourceType": "industry-report",
   "publisher": "Mordor Intelligence",
   "date": "2025-08-06",
   "excerpt": "Fastest Growing Market | Asia Pacific | ... Largest Market | North America",
   "url": "https://www.mordorintelligence.com/industry-reports/intelligent-pdu-market",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 320,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 520
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €320M",
   "crossCheck": "Europe DC PDUs+PSUs $2.45B 2024 (BIS/R&M, broader scope) × ~55% PDU share × 39.8% CE ≈ €495M — sets the high end of the band"
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; both sizing chains are scope-downs from adjacent scopes → wide band, top value-of-information.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
